    19→// ValidateLLMModel performs comprehensive validation of an LLM model
    20→func (v *LLMModelValidator) ValidateLLMModel(model *models.LLMModel) error {
    21→	if model == nil {
    22→		return fmt.Errorf("model cannot be nil")
    23→	}
    24→
    25→	// Run the model's built-in validation first
    26→	if err := model.Validate(); err != nil {
    27→		return err
    28→	}
    29→
    30→	// Additional validations
    31→	if err := v.validateModelID(model.ID); err != nil {
    32→		return fmt.Errorf("invalid model ID: %w", err)
    33→	}
    34→
    35→	if err := v.validateProviderSpecificConfig(model.Provider, model.Config); err != nil {
    36→		return fmt.Errorf("invalid provider config: %w", err)
    37→	}
    38→
    39→	if err := v.validateCapabilitiesForProvider(model.Provider, model.Capabilities); err != nil {
    40→		return fmt.Errorf("invalid capabilities for provider: %w", err)
    41→	}
    42→
    43→	if err := v.validateTokenLimits(model.MaxTokens, model.Provider); err != nil {
    44→		return fmt.Errorf("invalid token limits: %w", err)
    45→	}
    46→
    47→	return nil
    48→}
