    75→// validateProviderSpecificConfig validates configuration based on provider
    76→func (v *LLMModelValidator) validateProviderSpecificConfig(provider string, config map[string]string) error {
    77→	switch provider {
    78→	case "openai":
    79→		return v.validateOpenAIConfig(config)
    80→	case "anthropic":
    81→		return v.validateAnthropicConfig(config)
    82→	case "azure":
    83→		return v.validateAzureConfig(config)
    84→	case "local":
    85→		return v.validateLocalConfig(config)
    86→	default:
    87→		// For unknown providers, just check for basic config structure
    88→		return nil
    89→	}
    90→}
