    96→		"api_base":     true,
    97→		"api_version":  true,
    98→		"organization": true,
    99→		"temperature":  true,
   100→		"top_p":        true,
   101→		"max_retries":  true,
   102→	}
   103→
   104→	for key := range config {
   105→		if !validKeys[key] {
   106→			return fmt.Errorf("invalid OpenAI config key: %s", key)
   107→		}
   108→	}
   109→
   110→	return nil
   111→}
